import { Routes } from '@angular/router';
import { AuthGuard } from './core/guards/auth.guard';

export const routes: Routes = [
  {
    path: 'auth',
    // Usamos 'login' porque tu archivo se llama login.ts y la clase Login
    loadComponent: () => import('./features/auth/login/login').then(m => m.Login)
  },
  {
    path: 'proyectos',
    canActivate: [AuthGuard],
    // Ajustá esta ruta según cómo se llame tu archivo de proyectos
    // Si el archivo se llama proyectos.ts, dejalo así:
    loadComponent: () => import('./features/proyectos/proyectos').then(m => m.ProyectosComponent)
  },
  {
    path: '',
    redirectTo: 'auth',
    pathMatch: 'full'
  },
  {
    path: '**',
    redirectTo: 'auth'
  }
];
